(window.webpackJsonp=window.webpackJsonp||[]).push([[841],{1110:function(n){n.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * // Definition for a Node.\\n * function Node(val,prev,next,child) {\\n *    this.val = val;\\n *    this.prev = prev;\\n *    this.next = next;\\n *    this.child = child;\\n * };\\n */</span>\\n<span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{Node}</span> <span class=\\"hljs-variable\\">head</span></span>\\n * <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{Node}</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> flatten = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">head</span>) </span>{\\n  <span class=\\"hljs-keyword\\">return</span> _flatten(head)[<span class=\\"hljs-number\\">0</span>]\\n  <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> <span class=\\"hljs-title\\">_flatten</span>(<span class=\\"hljs-params\\">head</span>)</span>{\\n    <span class=\\"hljs-keyword\\">let</span> root=head,tail=<span class=\\"hljs-literal\\">null</span>\\n    <span class=\\"hljs-keyword\\">while</span>(root){\\n      <span class=\\"hljs-keyword\\">let</span> nxt=root.next\\n      <span class=\\"hljs-keyword\\">if</span>(root.child){\\n        <span class=\\"hljs-keyword\\">let</span> [subHead,subTail]=_flatten(root.child)\\n        root.child=<span class=\\"hljs-literal\\">null</span>\\n        root.next=subHead\\n        subHead.prev=root\\n        subTail.next=nxt\\n        <span class=\\"hljs-keyword\\">if</span>(nxt)nxt.prev=subTail\\n        <span class=\\"hljs-keyword\\">else</span> tail=subTail\\n      }\\n      <span class=\\"hljs-keyword\\">if</span>(!nxt &amp;&amp; !tail)tail=root\\n      root=nxt\\n    }    \\n    <span class=\\"hljs-keyword\\">return</span> [head,tail]\\n  }\\n\\n};\\n</code></pre>\\n"],"titleSlug":"flatten-a-multilevel-doubly-linked-list","hasThinking":true,"thinking":"<hr>\\n<p>\u601d\u8def\uff1a</p>\\n<p>\u904d\u5386<code>root</code>\uff0c\u53d1\u73b0\u5b58\u5728<code>child</code>\uff0c\u5219\u9012\u5f52<code>child</code>\uff0c2\u4e2a\u6ce8\u610f\u7684\u5730\u65b9\uff1a</p>\\n<ol>\\n<li>\u6bcf\u6b21\u9012\u5f52\u5904\u7406\u5b8c<code>child</code>\uff0c\u9700\u8981\u5c06<code>root.child</code>\u8bbe\u7f6e\u4e3a<code>null</code>\u3002</li>\\n<li>\u6bcf\u6b21\u9012\u5f52\u5904\u7406\u5b8c<code>child</code>\u7684\u8fd4\u56de\u503c\u9700\u8981\u4e00\u4e2a\u5934\uff0c\u4e00\u4e2a\u5c3e\uff0c\u5206\u522b**\u53cc\u5411\u8fde\u63a5*\u5904\u7406<code>child</code>\u4e4b\u524d\u7684<code>root</code>\u548c<code>root.next</code>\u3002</li>\\n</ol>\\n","content":"<p>\u591a\u7ea7\u53cc\u5411\u94fe\u8868\u4e2d\uff0c\u9664\u4e86\u6307\u5411\u4e0b\u4e00\u4e2a\u8282\u70b9\u548c\u524d\u4e00\u4e2a\u8282\u70b9\u6307\u9488\u4e4b\u5916\uff0c\u5b83\u8fd8\u6709\u4e00\u4e2a\u5b50\u94fe\u8868\u6307\u9488\uff0c\u53ef\u80fd\u6307\u5411\u5355\u72ec\u7684\u53cc\u5411\u94fe\u8868\u3002\u8fd9\u4e9b\u5b50\u5217\u8868\u4e5f\u53ef\u80fd\u4f1a\u6709\u4e00\u4e2a\u6216\u591a\u4e2a\u81ea\u5df1\u7684\u5b50\u9879\uff0c\u4f9d\u6b64\u7c7b\u63a8\uff0c\u751f\u6210\u591a\u7ea7\u6570\u636e\u7ed3\u6784\uff0c\u5982\u4e0b\u9762\u7684\u793a\u4f8b\u6240\u793a\u3002</p>\\n\\n<p>\u7ed9\u4f60\u4f4d\u4e8e\u5217\u8868\u7b2c\u4e00\u7ea7\u7684\u5934\u8282\u70b9\uff0c\u8bf7\u4f60\u6241\u5e73\u5316\u5217\u8868\uff0c\u4f7f\u6240\u6709\u7ed3\u70b9\u51fa\u73b0\u5728\u5355\u7ea7\u53cc\u94fe\u8868\u4e2d\u3002</p>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>head = [1,2,3,4,5,6,null,null,null,7,8,9,10,null,null,11,12]\\n<strong>\u8f93\u51fa\uff1a</strong>[1,2,3,7,8,11,12,9,10,4,5,6]\\n<strong>\u89e3\u91ca\uff1a\\n</strong>\\n\u8f93\u5165\u7684\u591a\u7ea7\u5217\u8868\u5982\u4e0b\u56fe\u6240\u793a\uff1a\\n\\n<img src=\\"https://assets.leetcode-cn.com/aliyun-lc-upload/uploads/2018/10/12/multilevellinkedlist.png\\" style=\\"height: 363px; width: 640px;\\">\\n\\n\u6241\u5e73\u5316\u540e\u7684\u94fe\u8868\u5982\u4e0b\u56fe\uff1a\\n\\n<img src=\\"https://assets.leetcode-cn.com/aliyun-lc-upload/uploads/2018/10/12/multilevellinkedlistflattened.png\\" style=\\"height: 80px; width: 1100px;\\">\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 2\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>head = [1,2,null,3]\\n<strong>\u8f93\u51fa\uff1a</strong>[1,3,2]\\n<strong>\u89e3\u91ca\uff1a\\n\\n</strong>\u8f93\u5165\u7684\u591a\u7ea7\u5217\u8868\u5982\u4e0b\u56fe\u6240\u793a\uff1a\\n\\n  1---2---NULL\\n  |\\n  3---NULL\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 3\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>head = []\\n<strong>\u8f93\u51fa\uff1a</strong>[]\\n</pre>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u5982\u4f55\u8868\u793a\u6d4b\u8bd5\u7528\u4f8b\u4e2d\u7684\u591a\u7ea7\u94fe\u8868\uff1f</strong></p>\\n\\n<p>\u4ee5 <strong>\u793a\u4f8b 1</strong> \u4e3a\u4f8b\uff1a</p>\\n\\n<pre> 1---2---3---4---5---6--NULL\\n         |\\n         7---8---9---10--NULL\\n             |\\n             11--12--NULL</pre>\\n\\n<p>\u5e8f\u5217\u5316\u5176\u4e2d\u7684\u6bcf\u4e00\u7ea7\u4e4b\u540e\uff1a</p>\\n\\n<pre>[1,2,3,4,5,6,null]\\n[7,8,9,10,null]\\n[11,12,null]\\n</pre>\\n\\n<p>\u4e3a\u4e86\u5c06\u6bcf\u4e00\u7ea7\u90fd\u5e8f\u5217\u5316\u5230\u4e00\u8d77\uff0c\u6211\u4eec\u9700\u8981\u6bcf\u4e00\u7ea7\u4e2d\u6dfb\u52a0\u503c\u4e3a null \u7684\u5143\u7d20\uff0c\u4ee5\u8868\u793a\u6ca1\u6709\u8282\u70b9\u8fde\u63a5\u5230\u4e0a\u4e00\u7ea7\u7684\u4e0a\u7ea7\u8282\u70b9\u3002</p>\\n\\n<pre>[1,2,3,4,5,6,null]\\n[null,null,7,8,9,10,null]\\n[null,11,12,null]\\n</pre>\\n\\n<p>\u5408\u5e76\u6240\u6709\u5e8f\u5217\u5316\u7ed3\u679c\uff0c\u5e76\u53bb\u9664\u672b\u5c3e\u7684 null \u3002</p>\\n\\n<pre>[1,2,3,4,5,6,null,null,null,7,8,9,10,null,null,11,12]</pre>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li>\u8282\u70b9\u6570\u76ee\u4e0d\u8d85\u8fc7 1000</li>\\n\\t<li><code>1 &lt;= Node.val &lt;= 10^5</code></li>\\n</ul>\\n","title":"430. \u6241\u5e73\u5316\u591a\u7ea7\u53cc\u5411\u94fe\u8868","relatedTags":["\u6df1\u5ea6\u4f18\u5148\u641c\u7d22","\u94fe\u8868"],"difficult":"Middle","lang":["javascript"],"uniqueID":"430"}')}}]);